106→ALFPHexTile* ALFPHexGridManager::SpawnTileAt(int32 Q, int32 R, ELFPTerrainType TerrainType,
107→	FName DecorationID, ELFPSpawnFaction SpawnFaction, int32 SpawnIndex, FGameplayTag EventTag)
108→{
109→	FIntPoint Key(Q, R);
110→	// 如果已存在则跳过
111→	if (GridMap.Contains(Key)) return GridMap[Key];
112→
113→	FLFPHexCoordinates HexCoord(Q, R);
114→	FVector WorldLocation = HexCoord.ToWorldLocation(HexSize, VerticalScale) + GetActorLocation();
115→
116→	FActorSpawnParameters SpawnParams;
117→	SpawnParams.Owner = this;
118→	ALFPHexTile* NewTile = GetWorld()->SpawnActor<ALFPHexTile>(
119→		HexTileClass,
120→		WorldLocation,
121→		FRotator::ZeroRotator,
122→		SpawnParams
123→	);
124→
125→	if (!NewTile) return nullptr;
126→
127→	NewTile->SetCoordinates(HexCoord);
128→	NewTile->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
129→
130→	// 应用地形：优先从注册表查找，否则用默认地形
131→	if (ULFPTerrainDataAsset* TerrainDA = GetTerrainDataForType(TerrainType))
132→	{
133→		NewTile->SetTerrainData(TerrainDA);
134→	}
135→	else if (DefaultTerrainData)
136→	{
137→		NewTile->SetTerrainData(DefaultTerrainData);
138→	}
139→
140→	// 应用装饰
141→	if (!DecorationID.IsNone())
142→	{
143→		NewTile->SetDecorationByID(DecorationID, GetDecorationSprite(DecorationID));
144→	}
145→
146→	// 应用出生点和事件数据
147→	NewTile->SpawnFaction = SpawnFaction;
148→	NewTile->SpawnIndex = SpawnIndex;
149→	NewTile->EventTag = EventTag;
150→
151→	GridMap.Add(Key, NewTile);
152→	return NewTile;
153→}
