161→bool ALFPHexGridManager::RemoveTile(int32 Q, int32 R)
162→{
163→	FIntPoint Key(Q, R);
164→	if (ALFPHexTile** Found = GridMap.Find(Key))
165→	{
166→		if (*Found)
167→		{
168→			(*Found)->Destroy();
169→		}
170→		GridMap.Remove(Key);
171→		return true;
172→	}
173→	return false;
174→}
