434→TArray<ALFPHexTile*> ALFPHexGridManager::FindPath(ALFPHexTile* Start, ALFPHexTile* End)
435→{
436→	TArray<ALFPHexTile*> Path;
437→
438→	// 验证输入有效性
439→	if (!Start || !End || !End->IsWalkable())
440→	{
441→		UE_LOG(LogTemp, Warning, TEXT("FindPath: Invalid start or end tile"));
442→		return Path;
443→	}
444→
445→	// 如果起点和终点相同
446→	if (Start == End) {
447→		Path.Add(Start);
448→		UE_LOG(LogTemp, Log, TEXT("FindPath: Start and end are the same tile"));
449→		return Path;
450→	}
451→
452→	// 寻路数据结构
453→	TMap<ALFPHexTile*, ALFPHexTile*> ParentMap;
454→	TMap<ALFPHexTile*, float> GScoreMap;  // 实际移动代价
455→	TSet<ALFPHexTile*> OpenSet;
456→	TSet<ALFPHexTile*> ClosedSet;
457→
458→	// 初始化起点
459→	OpenSet.Add(Start);
460→	GScoreMap.Add(Start, 0.0f);
461→	ParentMap.Add(Start, nullptr);
462→
463→	bool bPathFound = false;
464→
465→	while (!OpenSet.IsEmpty())
466→	{
467→		// 获取开放集中F值最小的节点
468→		ALFPHexTile* Current = nullptr;
469→		float LowestF = TNumericLimits<float>::Max();
470→
471→		for (ALFPHexTile* Tile : OpenSet)
472→		{
473→			const float G = GScoreMap[Tile];
474→			const float H = FLFPHexCoordinates::Distance(Tile->GetCoordinates(), End->GetCoordinates());
475→			const float F = G + H;
476→
477→			if (F < LowestF)
478→			{
479→				LowestF = F;
480→				Current = Tile;
481→			}
482→		}
483→
484→		// 到达终点
485→		if (Current == End)
486→		{
487→			bPathFound = true;
488→			ALFPHexTile* PathNode = End;
489→			while (PathNode)
490→			{
491→				Path.Add(PathNode);
492→				PathNode = ParentMap[PathNode];
493→			}
494→			Algo::Reverse(Path);
495→			break;
496→		}
497→
498→		// 移动节点到关闭集
499→		OpenSet.Remove(Current);
500→		ClosedSet.Add(Current);
501→
502→		// 遍历所有邻居
503→		for (const FLFPHexCoordinates& Dir : HexDirections)
504→		{
505→			FLFPHexCoordinates NeighborCoords = Current->GetCoordinates();
506→			NeighborCoords.Q += Dir.Q;
507→			NeighborCoords.R += Dir.R;
508→			NeighborCoords.S = -NeighborCoords.Q - NeighborCoords.R;  // 重新计算立方坐标
509→
510→			ALFPHexTile* Neighbor = GetTileAtCoordinates(NeighborCoords);
511→
512→			// 跳过无效邻居
513→			if (!Neighbor ||
514→				!Neighbor->IsWalkable() ||
515→				Neighbor->IsOccupied() ||
516→				ClosedSet.Contains(Neighbor))
517→			{
518→				continue;
519→			}
520→
521→			// 计算新G值（使用地形移动代价）
522→			const float TentativeG = GScoreMap[Current] + (float)Neighbor->GetMovementCost();
523→
524→			// 发现新节点或找到更短路径
525→			if (!OpenSet.Contains(Neighbor) || TentativeG < GScoreMap[Neighbor])
526→			{
527→				ParentMap.Add(Neighbor, Current);
528→				GScoreMap.Add(Neighbor, TentativeG);
529→
530→				if (!OpenSet.Contains(Neighbor)) {
531→					OpenSet.Add(Neighbor);
532→				}
533→			}
534→		}
535→	}
536→
537→	Path.Remove(Start);
538→	// 调试绘制路径
539→	//DrawDebugPath(Path, bPathFound);
540→
541→	if (bPathFound) {
542→		UE_LOG(LogTemp, Log, TEXT("FindPath: Found path with %d tiles"), Path.Num());
543→	}
544→	else {
545→		UE_LOG(LogTemp, Warning, TEXT("FindPath: No valid path found"));
546→	}
547→
548→	return Path;
549→}
