551→void ALFPHexGridManager::DrawDebugHexagon(const FVector& Center, FColor Color) const
552→{
553→	const float AngleStep = 60.0f;
554→	const float HorizontalRadius = HexSize; // 水平方向半径不变
555→	const float VerticalRadius = HexSize * VerticalScale; // 垂直方向半径缩放
556→
557→	// 添加 30° 偏移，使六边形正确朝向
558→	const float AngleOffset = 30.0f;
559→
560→	TArray<FVector> Points;
561→	for (int32 i = 0; i < 6; i++)
562→	{
563→		// 添加 30° 偏移
564→		float Angle = FMath::DegreesToRadians(AngleStep * i + AngleOffset);
565→		FVector Point(
566→			Center.X + HorizontalRadius * FMath::Cos(Angle),
567→			Center.Y + VerticalRadius * FMath::Sin(Angle), // 应用垂直缩放
568→			Center.Z
569→		);
570→		Points.Add(Point);
571→	}
572→
573→	// 连接点形成六边形
574→	for (int32 i = 0; i < 6; i++)
575→	{
576→		int32 NextIndex = (i + 1) % 6;
577→		DrawDebugLine(GetWorld(), Points[i], Points[NextIndex], Color, false, -1, 0, 2);
578→	}
579→}
