715→// 像素位置转换为六边形坐标
716→FLFPHexCoordinates ALFPHexGridManager::PixelToHexCoordinates(const FVector2D& PixelPosition, float InHexSize)
717→{
718→    // 获取像素值
719→    float x = PixelPosition.X;
720→    float y = PixelPosition.Y;
721→
722→    // 转换为立方坐标 - 尖顶六边形公式
723→    float q = (2.0f / 3.0f) * x;
724→    float r = (-1.0f / 3.0f) * x + (FMath::Sqrt(3.0f) / 3.0f) * y;
725→
726→    // 使用优化后的四舍五入到最近坐标
727→    return RoundToHex(q, r);
728→}
