404→void ALFPTacticsPlayerController::OnCameraPan(const FInputActionValue& Value)
405→{
406→    // 获取输入值（WASD/方向键）
407→    const FVector2D PanValue = Value.Get<FVector2D>();
408→
409→    // 计算移动方向（基于当前相机旋转）
410→    FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
411→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
412→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
413→
414→    // 计算移动偏移
415→    FVector PanDirection = (Forward * PanValue.Y) + (Right * PanValue.X);
416→    PanDirection.Z = 0;
417→    PanDirection.Normalize();
418→
419→    // 应用移动
420→    CameraOffset += PanDirection * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
421→}
